    users.name AS users_name,
    stuff_1.id AS stuff_1_id,
    stuff_1.date AS stuff_1_date,
    stuff_1.user_id AS stuff_1_user_id
FROM
    users
    LEFT JOIN stuff AS stuff_1
    ON
        users.id = stuff_1.user_id
        AND stuff_1.id
            = (
                    SELECT
                        stuff_2.id
                    FROM
                        stuff AS stuff_2
                    WHERE
                        stuff_2.user_id = users.id
                    ORDER BY
                        stuff_2.date DESC
                    LIMIT
                        1
