-- sqlfmt-corpus-separator --

SELECT task0_.id AS id1_2_, task0_.description AS descript2_2_, task0_.patient_id AS patient_3_2_
FROM task AS task0_ WHERE EXISTS (
	SELECT task1_.id FROM task AS task1_
	LEFT JOIN patient AS patient2_
	ON task1_.patient_id = patient2_.id
	LEFT JOIN site AS site3_
	ON patient2_.site_id = site3_.id
	WHERE (task1_.id = task0_.id) AND ((patient2_.id IS NULL) OR (site3_.id IN (2, 1)))
);

-- sqlfmt-corpus-separator --

SELECT tbl, idx, (i.keys).n
  FROM (SELECT ct.relname AS tbl, ct2.relname AS idx, information_schema._pg_expandarray(indkey) AS keys
          FROM pg_index ix
          JOIN pg_class ct ON ix.indrelid = ct.oid AND ct.relname = 'vals'
	  JOIN pg_class ct2 ON ix.indexrelid = ct2.oid) AS i
ORDER BY 1,2,3

-- sqlfmt-corpus-separator --

SELECT tc.relname AS table_name,
       regexp_replace(ic.relname, 'crdb_internal_index_\d+_name_placeholder', 'crdb_internal_temp_index') AS index_name,
       i.indisvalid, i.indisready, i.indislive
FROM pg_catalog.pg_index i
JOIN pg_catalog.pg_class tc ON tc.oid = i.indrelid
JOIN pg_catalog.pg_class ic ON ic.oid = i.indexrelid
WHERE i.indrelid = 'pg_index_backfill_test'::regclass
AND i.indisprimary = false
ORDER BY ic.relname

-- sqlfmt-corpus-separator --

SELECT tc.relname AS table_name, ic.relname AS index_name,
       i.indisvalid, i.indisready, i.indislive
FROM pg_catalog.pg_index i
JOIN pg_catalog.pg_class tc ON tc.oid = i.indrelid
JOIN pg_catalog.pg_class ic ON ic.oid = i.indexrelid
WHERE i.indrelid = 'pg_index_backfill_test'::regclass
AND i.indisprimary = false
ORDER BY ic.relname

-- sqlfmt-corpus-separator --

SELECT tc.table_schema, tc.table_name, cc.constraint_name, cc.check_clause
FROM information_schema.table_constraints AS tc
JOIN information_schema.check_constraints AS cc
USING (constraint_catalog, constraint_schema, constraint_name)
WHERE tc.table_schema in ('public')
ORDER BY tc.table_schema, tc.table_name, cc.constraint_name

