WITH
  with2
    AS (
      SELECT
        tq.trid, tq.dec1
      FROM
        trrec AS r INNER JOIN trtab4 AS tq ON r.id = tq.trid AND r.str16 = '12345'
    )
SELECT tr.id, tr.trid, val3.ts12
FROM
  trrec AS tr
  INNER JOIN LATERAL (
      SELECT  q.dec1 FROM with2 AS q WHERE tr.id = q.trid
    ) AS q ON true
  INNER JOIN LATERAL (
      SELECT
        m.ts12
      FROM trm AS m WHERE tr.id = m.trid
      ORDER BY m.ts12 ASC
      LIMIT 1
    ) AS val3 ON true
WHERE
  tr.str16 = '12345'
ORDER BY 1 DESC
;

