WITH a (colA) AS (
	VALUES ('row-1'), ('row-2')
),
b (colB) AS (
	VALUES ('row-1'), ('row-2')
)
SELECT a.colA, l.colB, l.colB_agg, l.count
FROM a
LEFT JOIN LATERAL (
	SELECT colB, array_agg(colB) AS colB_agg, count(*) AS count
	FROM b
	WHERE colB = a.colA
	GROUP BY colB
) l ON true
  -- redundant filter
	AND l.colB = a.colA;

